import fs from 'node:fs';
import path from 'node:path';

const root=process.cwd();
const required=['package.json','client/src/GameScene.ts','server/src/rooms/Drop8Room.ts','shared/src/index.ts'];
for(const file of required){
  if(!fs.existsSync(path.join(root,file))){
    console.error(`[PATCH ERROR] 프로젝트 루트에서 실행해야 합니다: ${file} 없음`);
    process.exit(1);
  }
}

const backupDir=path.join(root,'patch_backups','refactor_001');
fs.mkdirSync(backupDir,{recursive:true});

const files:Record<string,string>={
  "shared/src/index.ts": "export const GAME_NAME = 'DROP 8';\nexport const MAX_PLAYERS = 8;\nexport const WORLD_SIZE = 4096;\nexport const SERVER_TICK_RATE = 30;\nexport const PATCH_RATE_MS = 50;\nexport const CHAT_RADIUS = 700;\nexport const PLAYER_RADIUS = 22;\nexport const PLAYER_SPEED = 260;\nexport const PLANE_DURATION = 24;\nexport const FALL_START_ALTITUDE = 1000;\n\nexport type GamePhase = 'LOBBY' | 'PLANE' | 'DROP' | 'ACTIVE' | 'FINISHED';\nexport type PlayerPhase = 'lobby' | 'plane' | 'falling' | 'parachute' | 'landed' | 'dead';\nexport type Difficulty = 'easy' | 'normal' | 'hard';\nexport type ZoneSpeed = 'slow' | 'normal' | 'fast';\nexport type WeaponId = 'fists' | 'pistol' | 'smg' | 'rifle' | 'shotgun';\nexport type MeleeId = 'bat' | 'pan' | 'pipe' | 'knife';\nexport type EquippedId = WeaponId | MeleeId;\nexport type LootKind = WeaponId | MeleeId | 'small_ammo' | 'rifle_ammo' | 'shells' | 'vest' | 'bandage' | 'medkit';\n\nexport interface WeaponData {\n  id: WeaponId; name: string; damage: number; fireInterval: number; magazine: number;\n  reloadSeconds: number; spread: number; projectileSpeed: number; range: number;\n  pellets: number; moveMultiplier: number; ammoType: 'none' | 'small' | 'rifle' | 'shells'; slot: 'melee' | 'secondary' | 'primary';\n}\n\nexport interface MeleeData {\n  id: MeleeId; name: string; damage: number; fireInterval: number; range: number; arc: number; moveMultiplier: number;\n}\n\nexport const WEAPONS: Record<WeaponId, WeaponData> = {\n  fists: { id:'fists', name:'주먹', damage:10, fireInterval:.55, magazine:0, reloadSeconds:0, spread:0, projectileSpeed:0, range:65, pellets:1, moveMultiplier:1, ammoType:'none', slot:'melee' },\n  pistol:{ id:'pistol', name:'권총', damage:18, fireInterval:.28, magazine:12, reloadSeconds:1.35, spread:.025, projectileSpeed:1050, range:850, pellets:1, moveMultiplier:1, ammoType:'small', slot:'secondary' },\n  smg:{ id:'smg', name:'기관단총', damage:11, fireInterval:.085, magazine:30, reloadSeconds:1.55, spread:.08, projectileSpeed:920, range:680, pellets:1, moveMultiplier:1.05, ammoType:'small', slot:'primary' },\n  rifle:{ id:'rifle', name:'돌격소총', damage:17, fireInterval:.13, magazine:24, reloadSeconds:1.7, spread:.038, projectileSpeed:1100, range:980, pellets:1, moveMultiplier:.98, ammoType:'rifle', slot:'primary' },\n  shotgun:{ id:'shotgun', name:'샷건', damage:10, fireInterval:.72, magazine:5, reloadSeconds:2.0, spread:.24, projectileSpeed:820, range:420, pellets:7, moveMultiplier:.96, ammoType:'shells', slot:'primary' }\n};\n\nexport const MELEE_WEAPONS: Record<MeleeId, MeleeData> = {\n  bat:{id:'bat',name:'야구방망이',damage:24,fireInterval:.72,range:88,arc:1.15,moveMultiplier:1},\n  pan:{id:'pan',name:'프라이팬',damage:29,fireInterval:.88,range:72,arc:1.05,moveMultiplier:.97},\n  pipe:{id:'pipe',name:'쇠파이프',damage:22,fireInterval:.66,range:82,arc:1.1,moveMultiplier:.99},\n  knife:{id:'knife',name:'식칼',damage:17,fireInterval:.38,range:60,arc:.95,moveMultiplier:1.04}\n};\n\nexport const LOOT_LABELS: Record<LootKind,string> = {\n  fists:'주먹', pistol:'권총', smg:'기관단총', rifle:'돌격소총', shotgun:'샷건',\n  bat:'야구방망이', pan:'프라이팬', pipe:'쇠파이프', knife:'식칼',\n  small_ammo:'소형탄', rifle_ammo:'소총탄', shells:'산탄', vest:'방탄조끼', bandage:'붕대', medkit:'구급상자'\n};\n\nexport const LOOT_COLORS: Record<LootKind,number> = {\n  fists:0xf6f7f8, pistol:0xffd451, smg:0xffb84d, rifle:0xff8f4d, shotgun:0xff6b55,\n  bat:0xc98b55, pan:0xaeb9c2, pipe:0x8da0ad, knife:0xdde7ee,\n  small_ammo:0xffe88a, rifle_ammo:0xff9f64, shells:0xff6f7a, vest:0x73b9ff, bandage:0x58e49d, medkit:0x2ecf78\n};\n\nexport interface Rect { x:number; y:number; w:number; h:number; }\nexport interface Region { name:string; x:number; y:number; w:number; h:number; color:number; }\nexport type DoorSide = 'north'|'south'|'east'|'west';\nexport interface Building extends Rect { doorSide:DoorSide; doorOffset:number; doorWidth:number; }\n\nexport const REGIONS: Region[] = [\n  { name:'폐공장', x:220, y:260, w:980, h:800, color:0x5f6b73 },\n  { name:'주택가', x:1510, y:240, w:980, h:900, color:0x85755f },\n  { name:'병원', x:2890, y:300, w:760, h:720, color:0x668a8f },\n  { name:'창고지대', x:240, y:2520, w:1020, h:900, color:0x8a6b55 },\n  { name:'군사시설', x:1600, y:2650, w:930, h:900, color:0x5d6d57 },\n  { name:'숲속 캠프', x:2920, y:2500, w:820, h:980, color:0x3f704d }\n];\n\nconst RAW_BUILDINGS: Rect[] = [\n  {x:300,y:350,w:320,h:120},{x:720,y:380,w:340,h:100},{x:360,y:700,w:160,h:260},{x:760,y:690,w:290,h:190},\n  {x:1600,y:360,w:260,h:210},{x:1980,y:350,w:330,h:170},{x:1600,y:760,w:220,h:250},{x:2040,y:730,w:310,h:210},\n  {x:3010,y:420,w:520,h:180},{x:3100,y:730,w:180,h:230},{x:3390,y:720,w:180,h:230},\n  {x:330,y:2640,w:360,h:170},{x:780,y:2650,w:350,h:170},{x:400,y:3010,w:240,h:220},{x:810,y:3010,w:260,h:210},\n  {x:1690,y:2760,w:370,h:190},{x:2140,y:2760,w:280,h:190},{x:1710,y:3150,w:220,h:250},{x:2100,y:3150,w:300,h:220},\n  {x:3020,y:2660,w:170,h:170},{x:3350,y:2740,w:160,h:160},{x:3140,y:3100,w:170,h:170},{x:3500,y:3220,w:150,h:150},\n  {x:1350,y:1550,w:360,h:180},{x:2320,y:1450,w:190,h:390},{x:1750,y:1900,w:450,h:190}\n];\n\nconst DOOR_SIDES:DoorSide[]=['south','east','north','west'];\nexport const BUILDINGS:Building[] = RAW_BUILDINGS.map((r,i)=>({\n  ...r,\n  doorSide:DOOR_SIDES[i%DOOR_SIDES.length]!,\n  doorOffset:.5,\n  doorWidth:Math.max(72,Math.min(118,(i%2===0?r.w:r.h)*.36))\n}));\n\nconst WALL=18;\nfunction wallsForBuilding(b:Building):Rect[]{\n  const walls:Rect[]=[];\n  const addHorizontal=(y:number,door:boolean)=>{\n    if(!door){walls.push({x:b.x,y,w:b.w,h:WALL});return;}\n    const center=b.x+b.w*b.doorOffset,half=b.doorWidth/2;\n    const left=Math.max(0,center-half-b.x),rightStart=center+half;\n    if(left>0)walls.push({x:b.x,y,w:left,h:WALL});\n    if(rightStart<b.x+b.w)walls.push({x:rightStart,y,w:b.x+b.w-rightStart,h:WALL});\n  };\n  const addVertical=(x:number,door:boolean)=>{\n    if(!door){walls.push({x,y:b.y,w:WALL,h:b.h});return;}\n    const center=b.y+b.h*b.doorOffset,half=b.doorWidth/2;\n    const top=Math.max(0,center-half-b.y),bottomStart=center+half;\n    if(top>0)walls.push({x,y:b.y,w:WALL,h:top});\n    if(bottomStart<b.y+b.h)walls.push({x,y:bottomStart,w:WALL,h:b.y+b.h-bottomStart});\n  };\n  addHorizontal(b.y,b.doorSide==='north');\n  addHorizontal(b.y+b.h-WALL,b.doorSide==='south');\n  addVertical(b.x,b.doorSide==='west');\n  addVertical(b.x+b.w-WALL,b.doorSide==='east');\n  return walls;\n}\n\nexport const OBSTACLES:Rect[] = BUILDINGS.flatMap(wallsForBuilding);\n\nexport const LOOT_SPAWNS = Array.from({length: 76}, (_,i) => {\n  const r = REGIONS[i % REGIONS.length]!;\n  const col = i % 6, row = Math.floor(i / 6) % 5;\n  return { x: r.x + 90 + col * Math.max(95, (r.w-180)/6), y: r.y + 100 + row * Math.max(105, (r.h-200)/5), region: r.name };\n});\n\nconst SAFE_CHARS='ABCDEFGHJKLMNPQRSTUVWXYZ23456789';\nexport function createRoomCode(random=Math.random): string {\n  let result=''; for(let i=0;i<6;i++) result += SAFE_CHARS[Math.floor(random()*SAFE_CHARS.length)]; return result;\n}\nexport function sanitizeText(value:unknown,max=80):string { return String(value ?? '').replace(/[<>]/g,'').replace(/[\\u0000-\\u001F\\u007F]/g,'').trim().slice(0,max); }\nexport function clamp(n:number,min:number,max:number):number { return Math.max(min,Math.min(max,n)); }\nexport function distance(ax:number,ay:number,bx:number,by:number):number { return Math.hypot(ax-bx,ay-by); }\nexport function distanceSq(ax:number,ay:number,bx:number,by:number):number { const dx=ax-bx,dy=ay-by; return dx*dx+dy*dy; }\nexport function isFiniteNumber(v:unknown):v is number { return typeof v==='number' && Number.isFinite(v); }\nexport function circleHitsRect(x:number,y:number,r:number,rect:Rect):boolean { const nx=clamp(x,rect.x,rect.x+rect.w), ny=clamp(y,rect.y,rect.y+rect.h); return (x-nx)**2+(y-ny)**2 < r*r; }\n",
  "client/src/GameScene.ts": "import Phaser from 'phaser';\nimport {\n  BUILDINGS, LOOT_COLORS, LOOT_LABELS, MELEE_WEAPONS, OBSTACLES, REGIONS, WORLD_SIZE,\n  type EquippedId, type LootKind\n} from '@drop8/shared';\nimport type { Network } from './network';\n\ntype DisplayPoint={x:number;y:number};\n\nexport class GameScene extends Phaser.Scene {\n  private staticG!:Phaser.GameObjects.Graphics;\n  private dynamicG!:Phaser.GameObjects.Graphics;\n  private mini!:Phaser.GameObjects.Graphics;\n  private pickupText!:Phaser.GameObjects.Text;\n  private fpsText!:Phaser.GameObjects.Text;\n  private keys!:Record<string,Phaser.Input.Keyboard.Key>;\n  private seq=0;\n  private lastInput=0;\n  private lastFire=0;\n  private lastMiniDraw=0;\n  private mapOpen=false;\n  private spectateIndex=0;\n  private displayPlayers=new Map<string,DisplayPoint>();\n  private displayBullets=new Map<string,DisplayPoint>();\n  private lastAttackSeq=new Map<string,number>();\n  private attackStartedAt=new Map<string,number>();\n\n  constructor(private net:Network){super('game');}\n\n  create(){\n    this.cameras.main.setBounds(0,0,WORLD_SIZE,WORLD_SIZE);\n    this.cameras.main.setBackgroundColor('#153424');\n    this.staticG=this.add.graphics().setDepth(0);\n    this.dynamicG=this.add.graphics().setDepth(5);\n    this.mini=this.add.graphics().setScrollFactor(0).setDepth(40);\n    this.pickupText=this.add.text(this.scale.width/2,this.scale.height-92,'',{fontFamily:'sans-serif',fontSize:'18px',fontStyle:'bold',color:'#ffffff',backgroundColor:'#071018dd',padding:{x:12,y:8}}).setOrigin(.5).setScrollFactor(0).setDepth(50).setVisible(false);\n    this.fpsText=this.add.text(12,12,'',{fontFamily:'monospace',fontSize:'12px',color:'#9fb2bf',backgroundColor:'#071018aa',padding:{x:6,y:4}}).setScrollFactor(0).setDepth(50);\n    this.keys=this.input.keyboard!.addKeys('W,A,S,D,E,R,ONE,TWO,THREE,FOUR,M,SPACE,ENTER,LEFT,RIGHT') as Record<string,Phaser.Input.Keyboard.Key>;\n    this.keys.LEFT.on('down',()=>{this.spectateIndex=Math.max(0,this.spectateIndex-1);});\n    this.keys.RIGHT.on('down',()=>{this.spectateIndex++;});\n    this.keys.E.on('down',()=>this.net.send('pickup'));\n    this.keys.R.on('down',()=>this.net.send('reload'));\n    this.keys.ONE.on('down',()=>this.net.send('switch',{slot:1}));\n    this.keys.TWO.on('down',()=>this.net.send('switch',{slot:2}));\n    this.keys.THREE.on('down',()=>this.net.send('switch',{slot:3}));\n    this.keys.FOUR.on('down',()=>this.net.send('heal',{kind:'bandage'}));\n    this.keys.SPACE.on('down',()=>this.net.send('jump'));\n    this.keys.M.on('down',()=>{this.mapOpen=!this.mapOpen;this.lastMiniDraw=0;});\n    this.scale.on('resize',(size:Phaser.Structs.Size)=>{\n      this.pickupText.setPosition(size.width/2,size.height-92);\n      this.lastMiniDraw=0;\n    });\n    this.drawStaticMap();\n  }\n\n  update(time:number){\n    const s=this.net.snapshot;\n    if(!s)return;\n    const me=this.local();\n    if(me){\n      const alive=s.players.filter(p=>p.alive);\n      const target=me.alive?me:(alive.length?alive[this.spectateIndex%alive.length]:me);\n      const shown=this.getDisplayPlayer(target.id,target.x,target.y,me.id===target.id ? .42 : .24);\n      this.cameras.main.centerOn(shown.x,shown.y);\n      const pointer=this.input.activePointer;\n      const x=(this.keys.D.isDown?1:0)-(this.keys.A.isDown?1:0);\n      const y=(this.keys.S.isDown?1:0)-(this.keys.W.isDown?1:0);\n      if(time-this.lastInput>=50){\n        this.net.send('input',{x,y,angle:Math.atan2(pointer.worldY-me.y,pointer.worldX-me.x),seq:++this.seq});\n        this.lastInput=time;\n      }\n      if(pointer.isDown&&time-this.lastFire>=55){\n        this.net.send(me.equipped==='fists'||me.equipped in MELEE_WEAPONS?'melee':'fire');\n        this.lastFire=time;\n      }\n    }\n    this.drawDynamic(time);\n    this.updatePickupPrompt();\n    this.fpsText.setText(`FPS ${Math.round(this.game.loop.actualFps)}`);\n  }\n\n  private local(){return this.net.snapshot?.players.find(p=>p.id===this.net.sessionId);}\n\n  private drawStaticMap(){\n    const g=this.staticG;\n    g.clear();\n    g.fillStyle(0x153424).fillRect(0,0,WORLD_SIZE,WORLD_SIZE);\n    for(const r of REGIONS){\n      g.fillStyle(r.color,.22).fillRoundedRect(r.x,r.y,r.w,r.h,28);\n      g.lineStyle(3,0xffffff,.1).strokeRoundedRect(r.x,r.y,r.w,r.h,28);\n      this.add.text(r.x+20,r.y+18,r.name,{fontFamily:'sans-serif',fontSize:'30px',fontStyle:'bold',color:'#ffffff55'}).setDepth(.5);\n    }\n    for(const b of BUILDINGS){\n      g.fillStyle(0x26373d,.92).fillRect(b.x+18,b.y+18,Math.max(1,b.w-36),Math.max(1,b.h-36));\n      g.lineStyle(2,0x87a1ac,.2).strokeRect(b.x+18,b.y+18,Math.max(1,b.w-36),Math.max(1,b.h-36));\n    }\n    for(const wall of OBSTACLES){\n      g.fillStyle(0x4a5b63).fillRect(wall.x,wall.y,wall.w,wall.h);\n      g.lineStyle(2,0x10181d,.9).strokeRect(wall.x,wall.y,wall.w,wall.h);\n    }\n  }\n\n  private drawDynamic(time:number){\n    const s=this.net.snapshot;\n    if(!s)return;\n    const g=this.dynamicG;\n    g.clear();\n    const view=this.cameras.main.worldView;\n    const visible=(x:number,y:number,m=120)=>x>=view.x-m&&x<=view.right+m&&y>=view.y-m&&y<=view.bottom+m;\n\n    g.lineStyle(7,0x4db5ff,.78).strokeCircle(s.zoneX,s.zoneY,s.zoneRadius);\n    g.lineStyle(3,0xffffff,.22).strokeCircle(s.zoneX,s.zoneY,s.nextZoneRadius);\n\n    for(const l of s.loot){\n      if(!visible(l.x,l.y,70))continue;\n      this.drawLootIcon(g,l.kind as LootKind,l.x,l.y,1);\n    }\n\n    for(const b of s.bullets){\n      if(!visible(b.x,b.y,40))continue;\n      const d=this.getDisplayBullet(b.id,b.x,b.y);\n      g.lineStyle(3,0xffef9a,.9).lineBetween(d.x-b.vx*.012,d.y-b.vy*.012,d.x,d.y);\n      g.fillStyle(0xfff6bd).fillCircle(d.x,d.y,3);\n    }\n\n    if(['PLANE','DROP'].includes(s.phase)){\n      g.lineStyle(4,0xffffff,.2).lineBetween(0,s.planeY,s.planeEndX,s.planeEndY);\n      g.fillStyle(0xf1f3f4).fillTriangle(s.planeX+30,s.planeY,s.planeX-25,s.planeY-18,s.planeX-25,s.planeY+18);\n    }\n\n    const activeIds=new Set<string>();\n    for(const p of s.players){\n      if(!p.alive||!visible(p.x,p.y,100))continue;\n      activeIds.add(p.id);\n      const pos=this.getDisplayPlayer(p.id,p.x,p.y,p.id===this.net.sessionId ? .45 : .22);\n      this.drawPlayer(g,p,pos.x,pos.y,time);\n    }\n    for(const id of this.displayPlayers.keys())if(!activeIds.has(id)&&!s.players.some(p=>p.id===id))this.displayPlayers.delete(id);\n\n    if(time-this.lastMiniDraw>=100){\n      this.drawMini(s);\n      this.lastMiniDraw=time;\n    }\n  }\n\n  private drawPlayer(g:Phaser.GameObjects.Graphics,p:any,x:number,y:number,time:number){\n    const color=p.id===this.net.sessionId?0x45d7ff:p.ai?0xff8b5f:0xf06dba;\n    const scale=p.phase==='falling'?1.7:p.phase==='parachute'?1.35:1;\n    const altitudeOffset=20+Math.min(50,p.altitude/15);\n    g.fillStyle(0x000000,.22).fillEllipse(x,y+altitudeOffset,40,18);\n    g.fillStyle(color).fillCircle(x,y,20*scale);\n    g.lineStyle(4,0xffffff,p.id===this.net.sessionId?1:.38).strokeCircle(x,y,20*scale);\n\n    const attackSeq=Number(p.attackSeq??0);\n    const previous=this.lastAttackSeq.get(p.id);\n    if(previous===undefined)this.lastAttackSeq.set(p.id,attackSeq);\n    else if(previous!==attackSeq){this.lastAttackSeq.set(p.id,attackSeq);this.attackStartedAt.set(p.id,time);}\n    const started=this.attackStartedAt.get(p.id)??-999;\n    const attackProgress=Math.max(0,Math.min(1,(time-started)/170));\n    const attackPulse=attackProgress<1?Math.sin(attackProgress*Math.PI):0;\n    this.drawHeldItem(g,p.equipped as EquippedId,x,y,p.angle,attackPulse,attackSeq);\n\n    g.fillStyle(p.hp>40?0x55dd8c:0xff5f67).fillRect(x-25,y-37,50*Math.max(0,p.hp)/100,5);\n  }\n\n  private drawHeldItem(g:Phaser.GameObjects.Graphics,id:EquippedId,x:number,y:number,a:number,pulse:number,seq:number){\n    const pt=(forward:number,side:number)=>({x:x+Math.cos(a)*forward-Math.sin(a)*side,y:y+Math.sin(a)*forward+Math.cos(a)*side});\n    if(id==='fists'){\n      const side=seq%2===0?1:-1;\n      for(const hand of [-1,1]){\n        const extend=hand===side?22*pulse:0;\n        const elbow=pt(14+extend*.35,hand*12);\n        const fist=pt(24+extend,hand*12);\n        g.lineStyle(6,0xf0b28d,1).lineBetween(elbow.x,elbow.y,fist.x,fist.y);\n        g.fillStyle(0xffc39d).fillCircle(fist.x,fist.y,6);\n      }\n      return;\n    }\n\n    if(id in MELEE_WEAPONS){\n      const swing=a-.7+1.4*pulse;\n      const hand=pt(15,0);\n      const length=id==='knife'?34:id==='pan'?45:54;\n      const end={x:hand.x+Math.cos(swing)*length,y:hand.y+Math.sin(swing)*length};\n      g.lineStyle(id==='bat'?9:id==='pipe'?7:5,id==='bat'?0xc98b55:id==='pipe'?0x9eb1bb:0xd9e4ea,1).lineBetween(hand.x,hand.y,end.x,end.y);\n      if(id==='pan')g.fillStyle(0x9aaab4).fillCircle(end.x,end.y,13);\n      if(id==='knife')g.fillStyle(0xe9f1f5).fillTriangle(end.x,end.y,end.x-Math.cos(swing-.55)*15,end.y-Math.sin(swing-.55)*15,end.x-Math.cos(swing+.55)*15,end.y-Math.sin(swing+.55)*15);\n      return;\n    }\n\n    const recoil=4*pulse;\n    const hand=pt(15-recoil,0);\n    if(id==='pistol'){\n      const muzzle=pt(40-recoil,0),grip=pt(23-recoil,9);\n      g.lineStyle(7,0x222a31,1).lineBetween(hand.x,hand.y,muzzle.x,muzzle.y);\n      g.lineStyle(6,0x39454d,1).lineBetween(pt(23-recoil,1).x,pt(23-recoil,1).y,grip.x,grip.y);\n      g.fillStyle(0xffd451).fillCircle(muzzle.x,muzzle.y,3);\n    }else if(id==='smg'){\n      const end=pt(46-recoil,0),stock=pt(7-recoil,0),mag=pt(29-recoil,11);\n      g.lineStyle(10,0x303a42,1).lineBetween(stock.x,stock.y,end.x,end.y);\n      g.lineStyle(7,0x1e252b,1).lineBetween(pt(28-recoil,2).x,pt(28-recoil,2).y,mag.x,mag.y);\n      g.fillStyle(0xffb84d).fillCircle(end.x,end.y,3);\n    }else if(id==='rifle'){\n      const end=pt(58-recoil,0),stockTop=pt(4-recoil,-7),stockBottom=pt(4-recoil,7),stockBack=pt(-5-recoil,0),mag=pt(32-recoil,12);\n      g.lineStyle(7,0x303940,1).lineBetween(hand.x,hand.y,end.x,end.y);\n      g.lineStyle(5,0x4a3427,1).lineBetween(stockTop.x,stockTop.y,stockBack.x,stockBack.y).lineBetween(stockBack.x,stockBack.y,stockBottom.x,stockBottom.y);\n      g.lineStyle(6,0x1c2429,1).lineBetween(pt(31-recoil,2).x,pt(31-recoil,2).y,mag.x,mag.y);\n      g.fillStyle(0xff8f4d).fillCircle(end.x,end.y,3);\n    }else if(id==='shotgun'){\n      const endA=pt(58-recoil,-3),endB=pt(58-recoil,3),pump=pt(36-recoil,0);\n      g.lineStyle(5,0x30383e,1).lineBetween(hand.x,hand.y,endA.x,endA.y).lineBetween(hand.x,hand.y,endB.x,endB.y);\n      g.fillStyle(0x8b5b38).fillCircle(pump.x,pump.y,6);\n      g.fillStyle(0xff6b55).fillCircle(endA.x,endA.y,3).fillCircle(endB.x,endB.y,3);\n    }\n  }\n\n  private drawLootIcon(g:Phaser.GameObjects.Graphics,kind:LootKind,x:number,y:number,scale:number){\n    const c=LOOT_COLORS[kind]??0xffffff;\n    g.fillStyle(0x061018,.72).fillCircle(x,y,16*scale);\n    g.lineStyle(2,c,1);\n    const line=(x1:number,y1:number,x2:number,y2:number,w=3)=>{g.lineStyle(w,c,1).lineBetween(x+x1*scale,y+y1*scale,x+x2*scale,y+y2*scale);};\n    if(kind==='pistol'){line(-8,-2,8,-2,4);line(1,0,1,8,4);g.fillStyle(c).fillCircle(x+9*scale,y-2*scale,2.5*scale);}\n    else if(kind==='smg'){line(-10,0,10,0,6);line(1,2,1,10,4);line(-10,0,-14,5,3);g.fillStyle(c).fillCircle(x+11*scale,y,2.5*scale);}\n    else if(kind==='rifle'){line(-13,0,13,0,4);line(-13,0,-18,-6,3);line(2,1,2,10,4);g.fillStyle(c).fillCircle(x+14*scale,y,2.5*scale);}\n    else if(kind==='shotgun'){line(-14,-3,14,-3,3);line(-14,3,14,3,3);g.fillStyle(c).fillCircle(x+15*scale,y-3*scale,2).fillCircle(x+15*scale,y+3*scale,2);}\n    else if(kind==='small_ammo'||kind==='rifle_ammo'||kind==='shells'){for(const dx of [-6,0,6]){line(dx,-7,dx,6,3);g.fillStyle(c).fillCircle(x+dx*scale,y-7*scale,2*scale);}}\n    else if(kind==='vest'){g.fillStyle(c).fillTriangle(x-10*scale,y-9*scale,x+10*scale,y-9*scale,x,y+12*scale);g.fillStyle(0x061018).fillCircle(x,y-2*scale,4*scale);}\n    else if(kind==='bandage'){g.fillStyle(c).fillRoundedRect(x-11*scale,y-5*scale,22*scale,10*scale,4*scale);g.fillStyle(0xffffff).fillCircle(x,y,3*scale);}\n    else if(kind==='medkit'){g.fillStyle(c).fillRoundedRect(x-11*scale,y-11*scale,22*scale,22*scale,4*scale);g.lineStyle(4,0xffffff,1).lineBetween(x-6*scale,y,x+6*scale,y).lineBetween(x,y-6*scale,x,y+6*scale);}\n    else if(kind==='bat'){line(-11,8,11,-9,7);}\n    else if(kind==='pipe'){line(-11,8,11,-9,5);g.fillStyle(c).fillCircle(x+11*scale,y-9*scale,3*scale);}\n    else if(kind==='knife'){line(-10,8,2,-3,4);g.fillStyle(c).fillTriangle(x+2*scale,y-3*scale,x+13*scale,y-10*scale,x+7*scale,y+2*scale);}\n    else if(kind==='pan'){line(-11,10,3,-4,4);g.fillStyle(c).fillCircle(x+8*scale,y-9*scale,8*scale);}\n  }\n\n  private updatePickupPrompt(){\n    const s=this.net.snapshot,me=this.local();\n    if(!s||!me||!me.alive||me.phase!=='landed'){this.pickupText.setVisible(false);return;}\n    let nearest:any;let best=105*105;\n    for(const l of s.loot){const dx=l.x-me.x,dy=l.y-me.y,d=dx*dx+dy*dy;if(d<best){best=d;nearest=l;}}\n    if(!nearest){this.pickupText.setVisible(false);return;}\n    const label=LOOT_LABELS[nearest.kind as LootKind]??nearest.kind;\n    this.pickupText.setText(`E  줍기 · ${label}`).setVisible(true);\n  }\n\n  private getDisplayPlayer(id:string,x:number,y:number,alpha:number){\n    const current=this.displayPlayers.get(id)??{x,y};\n    current.x=Phaser.Math.Linear(current.x,x,alpha);\n    current.y=Phaser.Math.Linear(current.y,y,alpha);\n    this.displayPlayers.set(id,current);\n    return current;\n  }\n\n  private getDisplayBullet(id:string,x:number,y:number){\n    const current=this.displayBullets.get(id)??{x,y};\n    current.x=Phaser.Math.Linear(current.x,x,.55);\n    current.y=Phaser.Math.Linear(current.y,y,.55);\n    this.displayBullets.set(id,current);\n    return current;\n  }\n\n  private drawMini(s:any){\n    const g=this.mini;\n    g.clear();\n    const w=this.mapOpen?420:190,h=this.mapOpen?420:190,x=this.scale.width-w-14,y=14,sc=w/WORLD_SIZE;\n    g.fillStyle(0x061018,.9).fillRoundedRect(x,y,w,h,12);\n    for(const r of REGIONS)g.fillStyle(r.color,.45).fillRect(x+r.x*sc,y+r.y*sc,r.w*sc,r.h*sc);\n    for(const b of BUILDINGS)g.fillStyle(0x70818a,.52).fillRect(x+b.x*sc,y+b.y*sc,Math.max(1,b.w*sc),Math.max(1,b.h*sc));\n    g.lineStyle(2,0x4db5ff).strokeCircle(x+s.zoneX*sc,y+s.zoneY*sc,s.zoneRadius*sc);\n    for(const p of s.players){if(!p.alive)continue;g.fillStyle(p.id===this.net.sessionId?0x54dcff:0xff686e).fillCircle(x+p.x*sc,y+p.y*sc,p.id===this.net.sessionId?5:3);}\n  }\n}\n",
  "client/src/main.ts": "import Phaser from 'phaser';\nimport { GAME_NAME, MAX_PLAYERS, MELEE_WEAPONS, WEAPONS } from '@drop8/shared';\nimport { GameScene } from './GameScene';\nimport { Network } from './network';\nimport './style.css';\n\nconst $=<T extends HTMLElement>(id:string)=>document.getElementById(id) as T;\nconst net=new Network();\nlet game:Phaser.Game|null=null;\nlet chatting=false;\nlet lastHudAt=0;\nconst home=$('home'),lobby=$('lobby'),gameEl=$('game'),error=$('homeError');\nconst nickname=$<HTMLInputElement>('nickname'),roomCode=$<HTMLInputElement>('roomCode'),password=$<HTMLInputElement>('password');\nnickname.value=localStorage.getItem('drop8-nick')??'';\nroomCode.value=new URLSearchParams(location.search).get('room')??'';\n\nfunction nick(){const n=nickname.value.trim()||`유저${Math.floor(Math.random()*99)+1}`;localStorage.setItem('drop8-nick',n);return n;}\nasync function connect(create:boolean){\n  error.textContent='연결 중...';\n  try{\n    const opts={nickname:nick(),password:password.value,roomPassword:password.value,fillAi:true,difficulty:'normal',zoneSpeed:'normal'};\n    if(create)await net.create(opts);else await net.join(roomCode.value.trim(),opts);\n    home.classList.add('hidden');lobby.classList.remove('hidden');history.replaceState(null,'',`?room=${net.room?.roomId}`);error.textContent='';render();\n  }catch(e){error.textContent=e instanceof Error?e.message:'방 연결 실패';}\n}\n\n$('createBtn').onclick=()=>void connect(true);\n$('joinBtn').onclick=()=>void connect(false);\n$('readyBtn').onclick=()=>net.send('ready');\n$('startBtn').onclick=()=>net.send('start');\n$('copyBtn').onclick=()=>void navigator.clipboard.writeText(location.href);\n$('rematchBtn').onclick=()=>net.send('rematch');\n$('fillAi').onchange=sendSettings;\n$('difficulty').onchange=sendSettings;\n$('zoneSpeed').onchange=sendSettings;\nfunction sendSettings(){net.send('settings',{fillAi:($<HTMLInputElement>('fillAi')).checked,difficulty:($<HTMLSelectElement>('difficulty')).value,zoneSpeed:($<HTMLSelectElement>('zoneSpeed')).value});}\n\n$('lobbyChat').onsubmit=e=>{e.preventDefault();const i=$<HTMLInputElement>('lobbyChatInput');net.send('chat',{text:i.value});i.value='';};\n$('gameChat').onsubmit=e=>{e.preventDefault();const i=$<HTMLInputElement>('gameChatInput');net.send('chat',{text:i.value});i.value='';toggleChat(false);};\nwindow.addEventListener('keydown',e=>{\n  if(e.key==='Enter'&&!lobby.classList.contains('hidden'))return;\n  if(e.key==='Enter'&&!gameEl.classList.contains('hidden')){e.preventDefault();toggleChat(!chatting);}\n  if((e.key==='t'||e.key==='T')&&!gameEl.classList.contains('hidden')&&!chatting){e.preventDefault();$('quickChat').classList.toggle('hidden');}\n});\nfor(const button of Array.from(document.querySelectorAll<HTMLButtonElement>('#quickChat button'))){button.onclick=()=>{net.send('chat',{text:button.dataset.msg??''});$('quickChat').classList.add('hidden');};}\nfunction toggleChat(on:boolean){chatting=on;$('gameChat').classList.toggle('hidden',!on);if(on)$<HTMLInputElement>('gameChatInput').focus();}\n\nnet.listeners.add(render);\nnet.messages.add((type,p)=>{\n  if(type==='chat')addMessage(p);\n  if(type==='killfeed')addKill(p);\n  if(type==='result'){$('result').classList.remove('hidden');$('resultTitle').textContent=p.winner?`${p.winner} 우승!`:'경기 종료';$('resultStats').textContent=(p.placements??[]).map((n:string,i:number)=>`${i+1}위 ${n}`).join(' · ');}\n  if(type==='error')alert(p);\n});\n\nfunction addMessage(p:any){const box=net.snapshot?.phase==='LOBBY'?$('lobbyMessages'):$('gameMessages');const d=document.createElement('div');d.className=`message ${p.channel==='system'?'system':''}`;d.textContent=`[${p.sender}] ${p.text}`;box.append(d);while(box.children.length>30)box.firstChild?.remove();box.scrollTop=box.scrollHeight;setTimeout(()=>{if(box.id==='gameMessages')d.remove();},6500);}\nfunction addKill(p:any){const d=document.createElement('div');d.className='kill';d.textContent=`${p.killer} → ${p.victim}`;$('killfeed').append(d);setTimeout(()=>d.remove(),6000);}\n\nfunction createGame(){\n  game=new Phaser.Game({\n    type:Phaser.WEBGL,\n    parent:'gameCanvas',\n    width:window.innerWidth,\n    height:window.innerHeight,\n    backgroundColor:'#153424',\n    render:{antialias:false,roundPixels:true,powerPreference:'high-performance'},\n    fps:{target:60,smoothStep:true},\n    scene:new GameScene(net),\n    scale:{mode:Phaser.Scale.RESIZE,width:'100%',height:'100%'}\n  });\n}\n\nfunction render(){\n  const s=net.snapshot;if(!s)return;\n  $('codeText').textContent=`#${s.roomCode}`;\n  if(s.phase==='LOBBY'){\n    lobby.classList.remove('hidden');gameEl.classList.add('hidden');renderLobby(s);return;\n  }\n  lobby.classList.add('hidden');gameEl.classList.remove('hidden');\n  if(!game)createGame();\n  const now=performance.now();if(now-lastHudAt<100)return;lastHudAt=now;\n  const me=s.players.find(p=>p.id===net.sessionId);\n  $('phaseText').textContent=me&&!me.alive?'관전 중 · ← → 대상 변경':s.phase;\n  $('aliveText').textContent=String(s.aliveCount);\n  $('killsText').textContent=String(me?.kills??0);\n  $('zoneText').textContent=String(Math.max(0,Math.ceil(s.zoneTimer)));\n  $('hpText').textContent=String(Math.ceil(me?.hp??0));\n  $('armorText').textContent=String(Math.ceil(me?.armor??0));\n  const equipped=me?.equipped??'fists';\n  $('weaponText').textContent=WEAPONS[equipped as keyof typeof WEAPONS]?.name??MELEE_WEAPONS[equipped as keyof typeof MELEE_WEAPONS]?.name??equipped;\n  $('ammoText').textContent=equipped==='fists'||equipped in MELEE_WEAPONS?'':`${me?.magazine??0}발`;\n  if(s.phase==='FINISHED')$('result').classList.remove('hidden');\n}\n\nfunction renderLobby(s:any){\n  $('result').classList.add('hidden');\n  const me=s.players.find((p:any)=>p.id===net.sessionId),slots=$('slots');slots.innerHTML='';\n  for(let i=0;i<MAX_PLAYERS;i++){\n    const p=s.players[i],d=document.createElement('div');d.className=`slot ${p?'':'empty'}`;\n    d.innerHTML=p?`<span class=\"badge\">${p.host?'방장 · ':''}${p.ai?'AI':'PLAYER'}</span><br><b>${escapeText(p.name)}</b> · ${p.ready?'준비':'대기'}`:`빈 슬롯 ${i+1}`;slots.append(d);\n  }\n  $('startBtn').classList.toggle('hidden',!me?.host);\n  $('hostSettings').classList.toggle('hidden',!me?.host);\n  ($<HTMLInputElement>('fillAi')).checked=s.fillAi;\n  ($<HTMLSelectElement>('difficulty')).value=s.difficulty;\n  ($<HTMLSelectElement>('zoneSpeed')).value=s.zoneSpeed;\n}\nfunction escapeText(v:string){const d=document.createElement('div');d.textContent=v;return d.innerHTML;}\ndocument.title=GAME_NAME;\n",
  "client/src/network.ts": "import { Client, type Room } from '@colyseus/sdk';\nexport type Snapshot={phase:string;roomCode:string;hostId:string;fillAi:boolean;difficulty:string;zoneSpeed:string;zoneX:number;zoneY:number;zoneRadius:number;nextZoneRadius:number;zoneTimer:number;zoneStage:number;planeX:number;planeY:number;planeEndX:number;planeEndY:number;planeProgress:number;aliveCount:number;winner:string;players:any[];bullets:any[];loot:any[]};\nconst endpoint=location.origin.replace(/^http/,'ws');\nexport class Network {\n  client=new Client(endpoint); room:Room<any>|null=null; snapshot:Snapshot|null=null; listeners=new Set<()=>void>(); messages=new Set<(t:string,p:any)=>void>();\n  async create(options:any){this.room=await this.client.create('drop8',options);this.attach();return this.room;}\n  async join(code:string,options:any){this.room=await this.client.joinById(code.toUpperCase(),options);this.attach();return this.room;}\n  private attach(){if(!this.room)return;const update=(s:any)=>{this.snapshot=this.toSnapshot(s);this.listeners.forEach(fn=>fn());};this.room.onStateChange(update);if(this.room.state?.players)update(this.room.state);for(const type of ['chat','killfeed','result','error'])this.room.onMessage(type,(p:any)=>this.messages.forEach(fn=>fn(type,p)));}\n  private toSnapshot(s:any):Snapshot{const values=function(c:any){if(!c||typeof c.values!=='function')return [];return Array.from(c.values());};return {phase:s.phase,roomCode:s.roomCode,hostId:s.hostId,fillAi:s.fillAi,difficulty:s.difficulty,zoneSpeed:s.zoneSpeed,zoneX:s.zoneX,zoneY:s.zoneY,zoneRadius:s.zoneRadius,nextZoneRadius:s.nextZoneRadius,zoneTimer:s.zoneTimer,zoneStage:s.zoneStage,planeX:s.planeX,planeY:s.planeY,planeEndX:s.planeEndX,planeEndY:s.planeEndY,planeProgress:s.planeProgress,aliveCount:s.aliveCount,winner:s.winner,players:values(s.players).map((p:any)=>p.toJSON?.()??({...p})),bullets:values(s.bullets).map((b:any)=>b.toJSON?.()??({...b})),loot:values(s.loot).map((l:any)=>l.toJSON?.()??({...l}))};}\n  send(type:string,payload?:any){this.room?.send(type,payload);} get sessionId(){return this.room?.sessionId??'';}\n}\n",
  "server/src/rooms/schema.ts": "import { ArraySchema, MapSchema, Schema, type } from '@colyseus/schema';\n\nexport class PlayerState extends Schema {\n  @type('string') id=''; @type('string') name=''; @type('number') x=2048; @type('number') y=2048; @type('number') angle=0;\n  @type('number') hp=100; @type('number') armor=0; @type('number') altitude=0; @type('number') kills=0; @type('number') damageDone=0; @type('number') attackSeq=0;\n  @type('boolean') alive=true; @type('boolean') ready=false; @type('boolean') ai=false; @type('boolean') host=false; @type('boolean') muted=false;\n  @type('string') phase='lobby'; @type('string') primary=''; @type('string') secondary=''; @type('string') melee='fists'; @type('string') equipped='fists';\n  @type('number') magazine=0; @type('number') smallAmmo=0; @type('number') rifleAmmo=0; @type('number') shells=0; @type('number') bandages=0; @type('number') medkits=0;\n}\nexport class BulletState extends Schema { @type('string') id=''; @type('string') owner=''; @type('number') x=0; @type('number') y=0; @type('number') vx=0; @type('number') vy=0; @type('number') life=0; @type('number') damage=0; }\nexport class LootState extends Schema { @type('string') id=''; @type('string') kind=''; @type('number') x=0; @type('number') y=0; }\nexport class Drop8State extends Schema {\n  @type('string') phase='LOBBY'; @type('string') roomCode=''; @type('string') hostId=''; @type('boolean') fillAi=true; @type('string') difficulty='normal'; @type('string') zoneSpeed='normal';\n  @type({map:PlayerState}) players=new MapSchema<PlayerState>(); @type({map:BulletState}) bullets=new MapSchema<BulletState>(); @type({map:LootState}) loot=new MapSchema<LootState>();\n  @type('number') zoneX=2048; @type('number') zoneY=2048; @type('number') zoneRadius=1950; @type('number') nextZoneRadius=1950; @type('number') zoneTimer=30; @type('number') zoneStage=0;\n  @type('number') planeX=0; @type('number') planeY=0; @type('number') planeEndX=4096; @type('number') planeEndY=4096; @type('number') planeProgress=0;\n  @type('number') aliveCount=0; @type('string') winner=''; @type(['string']) placements=new ArraySchema<string>();\n}\n",
  "server/src/rooms/Drop8Room.ts": "import { Client, CloseCode, Room } from '@colyseus/core';\nimport { BulletState, Drop8State, LootState, PlayerState } from './schema.js';\nimport {\n  CHAT_RADIUS, FALL_START_ALTITUDE, LOOT_SPAWNS, MAX_PLAYERS, OBSTACLES, PATCH_RATE_MS, PLANE_DURATION,\n  PLAYER_RADIUS, PLAYER_SPEED, SERVER_TICK_RATE, MELEE_WEAPONS, WEAPONS, WORLD_SIZE, circleHitsRect, clamp, createRoomCode,\n  distance, isFiniteNumber, sanitizeText, type Difficulty, type LootKind, type MeleeId, type WeaponId, type ZoneSpeed\n} from '@drop8/shared';\n\ntype Input = { x:number; y:number; angle:number; seq:number };\ntype JoinOptions = { nickname?:unknown; password?:unknown; fillAi?:boolean; difficulty?:Difficulty; zoneSpeed?:ZoneSpeed; roomPassword?:unknown };\nconst AI_NAMES=['바람','돌멩이','야옹','쏜다','도망','파밍왕','생존봇'];\n\nexport class Drop8Room extends Room<{ state: Drop8State }> {\n  maxClients=MAX_PLAYERS; state=new Drop8State();\n  private inputs=new Map<string,Input>(); private shotAt=new Map<string,number>(); private reloadUntil=new Map<string,number>(); private healUntil=new Map<string,{at:number,amount:number}>();\n  private aiThinkAt=new Map<string,number>(); private chatAt=new Map<string,number>(); private password=''; private elapsed=0; private bulletSeq=0; private lootSeq=0; private planeStart={x:0,y:0}; private planeEnd={x:WORLD_SIZE,y:WORLD_SIZE};\n\n  async onCreate(options:JoinOptions) {\n    let code=createRoomCode();\n    for(let i=0;i<8 && await this.presence.get(`drop8:${code}`);i++) code=createRoomCode();\n    await this.presence.setex(`drop8:${code}`, '1', 60*60*8); this.roomId=code; this.state.roomCode=code;\n    this.state.fillAi=options.fillAi !== false; this.state.difficulty=options.difficulty ?? 'normal'; this.state.zoneSpeed=options.zoneSpeed ?? 'normal'; this.password=sanitizeText(options.roomPassword,32);\n    this.patchRate=PATCH_RATE_MS; this.setSimulationInterval(dt=>this.tick(dt/1000),1000/SERVER_TICK_RATE);\n    this.onMessage('ready',(c)=>this.ready(c)); this.onMessage('settings',(c,m)=>this.settings(c,m)); this.onMessage('start',(c)=>this.start(c));\n    this.onMessage('input',(c,m)=>this.input(c,m)); this.onMessage('jump',(c)=>this.jump(c)); this.onMessage('fire',(c)=>this.fire(c)); this.onMessage('melee',(c)=>this.melee(c));\n    this.onMessage('reload',(c)=>this.reload(c)); this.onMessage('pickup',(c)=>this.pickup(c)); this.onMessage('switch',(c,m)=>this.switchWeapon(c,m)); this.onMessage('heal',(c,m)=>this.heal(c,m));\n    this.onMessage('chat',(c,m)=>this.chat(c,m)); this.onMessage('rematch',(c)=>{if(this.state.phase==='FINISHED' && this.state.players.get(c.sessionId)?.host)this.resetLobby();});\n  }\n\n  onAuth(_client:Client, options:JoinOptions) { if(this.password && sanitizeText(options.password,32)!==this.password) throw new Error('비밀번호가 맞지 않습니다.'); return true; }\n  onJoin(client:Client, options:JoinOptions) {\n    const p=new PlayerState(); p.id=client.sessionId; p.name=sanitizeText(options.nickname,16)||`유저${this.clients.length}`; p.host=this.state.players.size===0;\n    this.state.players.set(client.sessionId,p); if(p.host)this.state.hostId=p.id; this.system(`${p.name}님이 입장했습니다.`);\n  }\n  async onLeave(client:Client, code:CloseCode) {\n    const p=this.state.players.get(client.sessionId); if(!p)return;\n    if(this.state.phase!=='LOBBY' && code!==CloseCode.CONSENTED) { try { await this.allowReconnection(client,15); return; } catch { /* reconnect timeout */ } }\n    const wasHost=p.host; this.state.players.delete(client.sessionId); this.inputs.delete(client.sessionId); this.system(`${p.name}님이 퇴장했습니다.`);\n    if(wasHost){ const next=[...this.state.players.values()].find(v=>!v.ai); if(next){next.host=true;this.state.hostId=next.id;} }\n  }\n  onDispose(){ void this.presence.del(`drop8:${this.roomId}`); }\n\n  private system(text:string){this.broadcast('chat',{channel:'system',sender:'시스템',text,time:Date.now()});}\n  private ready(c:Client){const p=this.state.players.get(c.sessionId);if(p&&this.state.phase==='LOBBY'){p.ready=!p.ready;this.system(`${p.name}님이 ${p.ready?'준비했습니다.':'준비를 취소했습니다.'}`);}}\n  private settings(c:Client,m:any){const p=this.state.players.get(c.sessionId);if(!p?.host||this.state.phase!=='LOBBY')return; if(typeof m?.fillAi==='boolean')this.state.fillAi=m.fillAi; if(['easy','normal','hard'].includes(m?.difficulty))this.state.difficulty=m.difficulty;if(['slow','normal','fast'].includes(m?.zoneSpeed))this.state.zoneSpeed=m.zoneSpeed;}\n  private start(c:Client){const p=this.state.players.get(c.sessionId);if(!p?.host||this.state.phase!=='LOBBY')return;const humans=[...this.state.players.values()].filter(v=>!v.ai);if(humans.some(v=>!v.ready)){c.send('error','모든 실제 플레이어가 준비해야 합니다.');return;} if(this.state.fillAi)this.fillAi();this.beginMatch();}\n  private fillAi(){let i=1;while(this.state.players.size<MAX_PLAYERS){const p=new PlayerState();p.id=`ai-${Date.now()}-${i}`;p.name=`AI-${AI_NAMES[(i-1)%AI_NAMES.length]}`;p.ai=true;p.ready=true;this.state.players.set(p.id,p);i++;}}\n  private beginMatch(){this.clearTransient();this.elapsed=0;this.state.phase='PLANE';this.state.winner='';this.state.placements.clear();this.state.zoneX=WORLD_SIZE/2;this.state.zoneY=WORLD_SIZE/2;this.state.zoneRadius=1950;this.state.nextZoneRadius=1950;this.state.zoneTimer=30;this.state.zoneStage=0;this.choosePlane();\n    let aiIndex=0;for(const p of this.state.players.values()){p.hp=100;p.armor=0;p.alive=true;p.kills=0;p.damageDone=0;p.attackSeq=0;p.phase='plane';p.altitude=FALL_START_ALTITUDE;p.primary='';p.secondary='';p.melee='fists';p.equipped='fists';p.magazine=0;p.smallAmmo=0;p.rifleAmmo=0;p.shells=0;p.bandages=0;p.medkits=0;p.x=this.planeStart.x;p.y=this.planeStart.y;if(p.ai)this.aiThinkAt.set(p.id,3+aiIndex++*1.7);}this.state.aliveCount=this.state.players.size;this.spawnLoot();this.system('비행기가 출발했습니다. Space로 낙하하세요.');}\n  private choosePlane(){const horizontal=Math.random()<.5;if(horizontal){const y=400+Math.random()*(WORLD_SIZE-800);this.planeStart={x:0,y};this.planeEnd={x:WORLD_SIZE,y:WORLD_SIZE-y};}else{const x=400+Math.random()*(WORLD_SIZE-800);this.planeStart={x,y:0};this.planeEnd={x:WORLD_SIZE-x,y:WORLD_SIZE};}this.state.planeX=this.planeStart.x;this.state.planeY=this.planeStart.y;this.state.planeEndX=this.planeEnd.x;this.state.planeEndY=this.planeEnd.y;this.state.planeProgress=0;}\n  private spawnLoot(){this.state.loot.clear();const weighted:LootKind[]=['pistol','pistol','smg','rifle','shotgun','small_ammo','small_ammo','rifle_ammo','shells','vest','bandage','bandage','medkit','bat','pan','pipe','knife'];for(const spawn of LOOT_SPAWNS){const l=new LootState();l.id=`loot-${++this.lootSeq}`;l.kind=weighted[Math.floor(Math.random()*weighted.length)]!;const pos=this.findLootPosition(spawn.x,spawn.y);l.x=pos.x;l.y=pos.y;this.state.loot.set(l.id,l);}}\n  private findLootPosition(baseX:number,baseY:number){for(let i=0;i<18;i++){const radius=i<4?70:70+i*16;const angle=i*2.399963;const x=clamp(baseX+Math.cos(angle)*radius*(i===0?0:1),40,WORLD_SIZE-40);const y=clamp(baseY+Math.sin(angle)*radius*(i===0?0:1),40,WORLD_SIZE-40);if(!OBSTACLES.some(r=>circleHitsRect(x,y,14,r)))return {x,y};}return {x:clamp(baseX,40,WORLD_SIZE-40),y:clamp(baseY,40,WORLD_SIZE-40)};}\n  private clearTransient(){this.state.bullets.clear();this.state.loot.clear();this.inputs.clear();this.shotAt.clear();this.reloadUntil.clear();this.healUntil.clear();}\n\n  private input(c:Client,m:any){const p=this.state.players.get(c.sessionId);if(!p||p.ai||!p.alive)return;if(!isFiniteNumber(m?.x)||!isFiniteNumber(m?.y)||!isFiniteNumber(m?.angle))return;this.inputs.set(p.id,{x:clamp(m.x,-1,1),y:clamp(m.y,-1,1),angle:m.angle,seq:Number(m.seq)||0});}\n  private jump(c:Client){const p=this.state.players.get(c.sessionId);if(p?.phase==='plane')this.doJump(p);}\n  private doJump(p:PlayerState){p.phase='falling';p.x=this.state.planeX;p.y=this.state.planeY;p.altitude=FALL_START_ALTITUDE;if(this.state.phase==='PLANE')this.state.phase='DROP';}\n  private fire(c:Client){const p=this.state.players.get(c.sessionId);if(p)this.firePlayer(p);}\n  private firePlayer(p:PlayerState){if(!p.alive||p.phase!=='landed'||this.reloadUntil.has(p.id)||this.healUntil.has(p.id))return;const w=WEAPONS[p.equipped as WeaponId];if(!w||w.id==='fists'||p.magazine<=0)return;const now=this.clock.elapsedTime/1000;if(now-(this.shotAt.get(p.id)??-99)<w.fireInterval)return;this.shotAt.set(p.id,now);p.attackSeq++;p.magazine--;for(let i=0;i<w.pellets;i++){const a=p.angle+(Math.random()*2-1)*w.spread;const b=new BulletState();b.id=`b-${++this.bulletSeq}`;b.owner=p.id;b.x=p.x+Math.cos(a)*28;b.y=p.y+Math.sin(a)*28;b.vx=Math.cos(a)*w.projectileSpeed;b.vy=Math.sin(a)*w.projectileSpeed;b.life=w.range/w.projectileSpeed;b.damage=w.damage;this.state.bullets.set(b.id,b);}}\n  private melee(c:Client){const p=this.state.players.get(c.sessionId);if(!p||!p.alive||p.phase!=='landed')return;const melee=p.equipped==='fists'?{name:'주먹',damage:WEAPONS.fists.damage,fireInterval:WEAPONS.fists.fireInterval,range:WEAPONS.fists.range,arc:1.1}:MELEE_WEAPONS[p.equipped as MeleeId];if(!melee)return;const now=this.clock.elapsedTime/1000;if(now-(this.shotAt.get(p.id)??-99)<melee.fireInterval)return;this.shotAt.set(p.id,now);p.attackSeq++;let target:PlayerState|undefined;let best=melee.range;for(const other of this.state.players.values()){if(!other.alive||other.id===p.id||other.phase!=='landed')continue;const d=distance(p.x,p.y,other.x,other.y);if(d<best&&Math.abs(this.angleDiff(Math.atan2(other.y-p.y,other.x-p.x),p.angle))<melee.arc){target=other;best=d;}}if(target)this.damage(target,melee.damage,p.id,p.equipped==='fists'?'주먹':melee.name);}\n  private reload(c:Client){const p=this.state.players.get(c.sessionId);if(!p)return;const w=WEAPONS[p.equipped as WeaponId];if(!w||w.id==='fists'||p.magazine>=w.magazine)return;const reserve=this.getAmmo(p,w.ammoType);if(reserve<=0)return;this.reloadUntil.set(p.id,this.clock.elapsedTime/1000+w.reloadSeconds);}\n  private pickup(c:Client){const p=this.state.players.get(c.sessionId);if(!p||p.phase!=='landed'||!p.alive)return;let pick:LootState|undefined,best=72;for(const l of this.state.loot.values()){const d=distance(p.x,p.y,l.x,l.y);if(d<best){best=d;pick=l;}}if(!pick)return;this.applyLoot(p,pick.kind as LootKind);this.state.loot.delete(pick.id);}\n  private applyLoot(p:PlayerState,k:LootKind){if(k in WEAPONS&&k!=='fists'){const w=WEAPONS[k as WeaponId];if(w.slot==='primary')p.primary=k;else p.secondary=k;p.equipped=k;p.magazine=w.magazine;if(w.ammoType==='small')p.smallAmmo+=w.magazine*2;if(w.ammoType==='rifle')p.rifleAmmo+=w.magazine*2;if(w.ammoType==='shells')p.shells+=w.magazine*2;return;}if(k in MELEE_WEAPONS){p.melee=k;p.equipped=k;return;}if(k==='small_ammo')p.smallAmmo+=30;else if(k==='rifle_ammo')p.rifleAmmo+=24;else if(k==='shells')p.shells+=12;else if(k==='vest')p.armor=Math.max(p.armor,100);else if(k==='bandage')p.bandages=Math.min(5,p.bandages+1);else if(k==='medkit')p.medkits=Math.min(2,p.medkits+1);}\n  private switchWeapon(c:Client,m:any){const p=this.state.players.get(c.sessionId);if(!p)return;const slot=Number(m?.slot);const id=slot===1?p.primary:slot===2?p.secondary:p.melee||'fists';if(!id)return;if(!(id in WEAPONS)&&!(id in MELEE_WEAPONS))return;p.equipped=id;const w=WEAPONS[id as WeaponId];if(w&&w.id!=='fists')p.magazine=Math.min(p.magazine,w.magazine);this.healUntil.delete(p.id);}\n  private heal(c:Client,m:any){const p=this.state.players.get(c.sessionId);if(!p||p.hp>=100||this.healUntil.has(p.id))return;const med=m?.kind==='medkit';if(med&&p.medkits>0){p.medkits--;this.healUntil.set(p.id,{at:this.clock.elapsedTime/1000+4,amount:60});}else if(!med&&p.bandages>0){p.bandages--;this.healUntil.set(p.id,{at:this.clock.elapsedTime/1000+2,amount:25});}}\n  private chat(c:Client,m:any){const p=this.state.players.get(c.sessionId);if(!p||p.muted)return;const text=sanitizeText(m?.text,80);if(!text)return;const now=Date.now();if(now-(this.chatAt.get(p.id)??0)<650)return;this.chatAt.set(p.id,now);if(this.state.phase==='LOBBY'){this.broadcast('chat',{channel:'lobby',sender:p.name,text,time:now});return;}if(!p.alive){for(const cl of this.clients){const q=this.state.players.get(cl.sessionId);if(q&&!q.alive)cl.send('chat',{channel:'spectator',sender:p.name,text,time:now});}return;}for(const cl of this.clients){const q=this.state.players.get(cl.sessionId);if(q?.alive&&distance(p.x,p.y,q.x,q.y)<=CHAT_RADIUS)cl.send('chat',{channel:'nearby',sender:p.name,text,time:now,playerId:p.id});}}\n\n  private tick(dt:number){if(this.state.phase==='LOBBY'||this.state.phase==='FINISHED')return;this.elapsed+=dt;this.updatePlane(dt);this.updatePlayers(dt);this.updateReloads();this.updateHeals();this.updateBullets(dt);this.updateZone(dt);this.updateAi(dt);this.finishCheck();}\n  private updatePlane(_dt:number){if(!['PLANE','DROP'].includes(this.state.phase))return;this.state.planeProgress=clamp(this.elapsed/PLANE_DURATION,0,1);this.state.planeX=this.planeStart.x+(this.planeEnd.x-this.planeStart.x)*this.state.planeProgress;this.state.planeY=this.planeStart.y+(this.planeEnd.y-this.planeStart.y)*this.state.planeProgress;for(const p of this.state.players.values()){if(p.phase==='plane'){p.x=this.state.planeX;p.y=this.state.planeY;if(p.ai && this.elapsed>=(this.aiThinkAt.get(p.id)??8))this.doJump(p);if(this.state.planeProgress>=1)this.doJump(p);}}}\n  private updatePlayers(dt:number){for(const p of this.state.players.values()){if(!p.alive)continue;const input=this.inputs.get(p.id)??{x:0,y:0,angle:p.angle,seq:0};p.angle=input.angle;if(p.phase==='falling'||p.phase==='parachute'){const parachute=p.altitude<300;p.phase=parachute?'parachute':'falling';const speed=parachute?145:260;this.tryMove(p,input.x*speed*dt,input.y*speed*dt);p.altitude=Math.max(0,p.altitude-(parachute?120:260)*dt);if(p.altitude<=0){p.phase='landed';this.system(`${p.name} 착지`);}continue;}if(p.phase!=='landed'||this.healUntil.has(p.id))continue;const ranged=WEAPONS[(p.equipped||'fists') as WeaponId],melee=MELEE_WEAPONS[p.equipped as MeleeId];const moveMultiplier=ranged?.moveMultiplier??melee?.moveMultiplier??1;this.tryMove(p,input.x*PLAYER_SPEED*moveMultiplier*dt,input.y*PLAYER_SPEED*moveMultiplier*dt);}}\n  private tryMove(p:PlayerState,dx:number,dy:number){const len=Math.hypot(dx,dy);if(len>18){dx=dx/len*18;dy=dy/len*18;}const nx=clamp(p.x+dx,PLAYER_RADIUS,WORLD_SIZE-PLAYER_RADIUS),ny=clamp(p.y+dy,PLAYER_RADIUS,WORLD_SIZE-PLAYER_RADIUS);if(!OBSTACLES.some(r=>circleHitsRect(nx,p.y,PLAYER_RADIUS,r)))p.x=nx;if(!OBSTACLES.some(r=>circleHitsRect(p.x,ny,PLAYER_RADIUS,r)))p.y=ny;}\n  private updateReloads(){const now=this.clock.elapsedTime/1000;for(const [id,until] of [...this.reloadUntil])if(now>=until){const p=this.state.players.get(id);if(p){const w=WEAPONS[p.equipped as WeaponId];if(w&&w.id!=='fists'){const need=w.magazine-p.magazine,res=this.getAmmo(p,w.ammoType),load=Math.min(need,res);p.magazine+=load;this.setAmmo(p,w.ammoType,res-load);}}this.reloadUntil.delete(id);}}\n  private updateHeals(){const now=this.clock.elapsedTime/1000;for(const [id,h] of [...this.healUntil])if(now>=h.at){const p=this.state.players.get(id);if(p?.alive)p.hp=Math.min(100,p.hp+h.amount);this.healUntil.delete(id);}}\n  private updateBullets(dt:number){for(const [id,b] of [...this.state.bullets]){const ox=b.x,oy=b.y;b.x+=b.vx*dt;b.y+=b.vy*dt;b.life-=dt;if(b.life<=0||b.x<0||b.y<0||b.x>WORLD_SIZE||b.y>WORLD_SIZE||OBSTACLES.some(r=>this.segmentRect(ox,oy,b.x,b.y,r))){this.state.bullets.delete(id);continue;}for(const p of this.state.players.values()){if(!p.alive||p.id===b.owner||p.phase!=='landed')continue;if(distance(b.x,b.y,p.x,p.y)<PLAYER_RADIUS+5){this.damage(p,b.damage,b.owner,'총기');this.state.bullets.delete(id);break;}}}}\n  private updateZone(dt:number){const landed=[...this.state.players.values()].some(p=>p.phase==='landed');if(!landed)return;const mult=this.state.zoneSpeed==='fast'?1.35:this.state.zoneSpeed==='slow'?.8:1;this.state.zoneTimer-=dt*mult;if(this.state.zoneTimer<=0&&this.state.zoneStage<6){this.state.zoneStage++;this.state.nextZoneRadius=Math.max(120,this.state.zoneRadius*(this.state.zoneStage===1?.68:.72));this.state.zoneTimer=this.state.zoneStage===1?52:42;this.state.zoneX=clamp(this.state.zoneX+(Math.random()-.5)*(this.state.zoneRadius-this.state.nextZoneRadius),this.state.nextZoneRadius,WORLD_SIZE-this.state.nextZoneRadius);this.state.zoneY=clamp(this.state.zoneY+(Math.random()-.5)*(this.state.zoneRadius-this.state.nextZoneRadius),this.state.nextZoneRadius,WORLD_SIZE-this.state.nextZoneRadius);}if(this.state.nextZoneRadius<this.state.zoneRadius)this.state.zoneRadius=Math.max(this.state.nextZoneRadius,this.state.zoneRadius-dt*(28+this.state.zoneStage*16)*mult);for(const p of this.state.players.values()){if(p.alive&&p.phase==='landed'&&distance(p.x,p.y,this.state.zoneX,this.state.zoneY)>this.state.zoneRadius)this.damage(p,(2+this.state.zoneStage*1.8)*dt,'','자기장');}}\n  private updateAi(dt:number){const now=this.clock.elapsedTime/1000;for(const p of this.state.players.values()){if(!p.ai||!p.alive||p.phase!=='landed')continue;if(now<(this.aiThinkAt.get(p.id)??0))continue;this.aiThinkAt.set(p.id,now+.24);let tx=this.state.zoneX,ty=this.state.zoneY;const outside=distance(p.x,p.y,this.state.zoneX,this.state.zoneY)>this.state.zoneRadius-160;let target:PlayerState|undefined,best=900;for(const q of this.state.players.values()){if(q.id===p.id||!q.alive||q.phase!=='landed')continue;const d=distance(p.x,p.y,q.x,q.y);if(d<best&&!OBSTACLES.some(r=>this.segmentRect(p.x,p.y,q.x,q.y,r))){best=d;target=q;}}if(!p.primary&&!p.secondary){let loot:LootState|undefined,ld=9999;for(const l of this.state.loot.values()){if(!['pistol','smg','rifle','shotgun'].includes(l.kind))continue;const d=distance(p.x,p.y,l.x,l.y);if(d<ld){ld=d;loot=l;}}if(loot){tx=loot.x;ty=loot.y;if(ld<70){this.applyLoot(p,loot.kind as LootKind);this.state.loot.delete(loot.id);}}}else if(target&&!outside){tx=target.x;ty=target.y;p.angle=Math.atan2(ty-p.y,tx-p.x);const desired=p.equipped==='shotgun'?190:430;if(best>desired)this.aiMove(p,tx,ty,dt);else if(best<desired*.55)this.aiMove(p,p.x-(tx-p.x),p.y-(ty-p.y),dt);this.firePlayer(p);continue;}if(outside||!target)this.aiMove(p,tx,ty,dt);}}\n  private aiMove(p:PlayerState,tx:number,ty:number,dt:number){const a=Math.atan2(ty-p.y,tx-p.x);p.angle=a;const speed=this.state.difficulty==='hard'?235:this.state.difficulty==='easy'?175:205;this.tryMove(p,Math.cos(a)*speed*dt,Math.sin(a)*speed*dt);}\n  private damage(p:PlayerState,amount:number,attackerId:string,reason:string){if(!p.alive)return;this.healUntil.delete(p.id);let actual=amount;if(p.armor>0&&reason==='총기'){const absorbed=actual*.3;actual-=absorbed;p.armor=Math.max(0,p.armor-absorbed*1.5);}p.hp-=actual;const attacker=this.state.players.get(attackerId);if(attacker)attacker.damageDone+=actual;if(p.hp<=0){p.hp=0;p.alive=false;p.phase='dead';this.state.placements.unshift(p.name);if(attacker&&attacker.id!==p.id){attacker.kills++;this.broadcast('killfeed',{killer:attacker.name,victim:p.name,reason});}else this.broadcast('killfeed',{killer:reason,victim:p.name,reason});this.dropInventory(p);}}\n  private dropInventory(p:PlayerState){const kinds=[p.primary,p.secondary,p.melee!=='fists'?p.melee:'',p.armor>0?'vest':'',p.bandages?'bandage':'',p.medkits?'medkit':''].filter(Boolean);for(const k of kinds){const l=new LootState();l.id=`loot-${++this.lootSeq}`;l.kind=k;l.x=clamp(p.x+(Math.random()-.5)*55,20,WORLD_SIZE-20);l.y=clamp(p.y+(Math.random()-.5)*55,20,WORLD_SIZE-20);this.state.loot.set(l.id,l);}}\n  private finishCheck(){const alive=[...this.state.players.values()].filter(p=>p.alive);this.state.aliveCount=alive.length;if(alive.length<=1&&this.state.players.size>1&&this.state.phase!=='FINISHED'){this.state.phase='FINISHED';this.state.winner=alive[0]?.name??'없음';if(alive[0])this.state.placements.unshift(alive[0].name);this.broadcast('result',{winner:this.state.winner,placements:[...this.state.placements]});}}\n  private resetLobby(){this.clearTransient();for(const [id,p] of [...this.state.players]){if(p.ai)this.state.players.delete(id);else{p.ready=false;p.alive=true;p.hp=100;p.phase='lobby';p.primary='';p.secondary='';p.melee='fists';p.equipped='fists';p.attackSeq=0;}}this.state.phase='LOBBY';this.state.winner='';this.state.placements.clear();this.state.aliveCount=this.state.players.size;}\n  private getAmmo(p:PlayerState,t:string){return t==='small'?p.smallAmmo:t==='rifle'?p.rifleAmmo:t==='shells'?p.shells:0;}\n  private setAmmo(p:PlayerState,t:string,v:number){if(t==='small')p.smallAmmo=v;else if(t==='rifle')p.rifleAmmo=v;else if(t==='shells')p.shells=v;}\n  private angleDiff(a:number,b:number){return Math.atan2(Math.sin(a-b),Math.cos(a-b));}\n  private segmentRect(x1:number,y1:number,x2:number,y2:number,r:{x:number;y:number;w:number;h:number}){const steps=Math.max(1,Math.ceil(distance(x1,y1,x2,y2)/18));for(let i=0;i<=steps;i++){const t=i/steps,x=x1+(x2-x1)*t,y=y1+(y2-y1)*t;if(x>=r.x&&x<=r.x+r.w&&y>=r.y&&y<=r.y+r.h)return true;}return false;}\n}\n"
};

for(const [relative,content] of Object.entries(files)){
  const target=path.join(root,relative);
  const backup=path.join(backupDir,relative);
  fs.mkdirSync(path.dirname(backup),{recursive:true});
  if(fs.existsSync(target))fs.copyFileSync(target,backup);
  fs.mkdirSync(path.dirname(target),{recursive:true});
  fs.writeFileSync(target,content,'utf8');
  console.log(`[PATCH] ${relative}`);
}

const stylePath=path.join(root,'client/src/style.css');
if(fs.existsSync(stylePath)){
  const backup=path.join(backupDir,'client/src/style.css');
  fs.mkdirSync(path.dirname(backup),{recursive:true});
  fs.copyFileSync(stylePath,backup);
  let style=fs.readFileSync(stylePath,'utf8');
  const replacement='#game{position:relative;width:100vw;height:100vh;min-height:100vh;overflow:hidden;background:#12271d}';
  if(/#game\{[^}]*\}/.test(style))style=style.replace(/#game\{[^}]*\}/,replacement);
  else style+='\n'+replacement+'\n';
  fs.writeFileSync(stylePath,style,'utf8');
  console.log('[PATCH] client/src/style.css');
}

const notesPath=path.join(root,'docs/PATCH_NOTES.md');
if(fs.existsSync(notesPath)){
  const marker='## refactor_001 - 렌더링·건물·아이템·전투 표현 개선';
  let notes=fs.readFileSync(notesPath,'utf8');
  if(!notes.includes(marker)){
    notes+=`

${marker}
- 정적 맵 1회 렌더링, 동적 객체 화면 컬링, 좌표 보간, 미니맵 10Hz 갱신
- 건물 벽을 문이 있는 4면 충돌 구조로 변경
- 아이템별 선·점·도형 아이콘 및 근처 E 획득 안내 추가
- 주먹 양팔/펀치 애니메이션 및 총기별 실루엣 추가
- 근접무기 데이터와 서버 판정 오류 수정
- AI 판단 주기 완화 및 아이템 벽 겹침 방지
`;
    fs.writeFileSync(notesPath,notes,'utf8');
  }
}

